    78→                                         Http::ConnectionPool::Callbacks& callbacks,
    79→                                         const Instance::StreamOptions& options) override;
    80→  bool maybePreconnect(float ratio) override { return maybePreconnectImpl(ratio); }
    81→  bool hasActiveConnections() const override;
