   112→// An implementation of Envoy::ConnectionPool::ActiveClient for HTTP/1.1 and HTTP/2
   113→class ActiveClient : public Envoy::ConnectionPool::ActiveClient {
   114→public:
   115→  ActiveClient(HttpConnPoolImplBase& parent, uint32_t lifetime_stream_limit,
   116→               uint32_t effective_concurrent_stream_limit,
   117→               uint32_t configured_concurrent_stream_limit,
   118→               OptRef<Upstream::Host::CreateConnectionData> opt_data)
   119→      : Envoy::ConnectionPool::ActiveClient(parent, lifetime_stream_limit,
   120→                                            effective_concurrent_stream_limit,
   121→                                            configured_concurrent_stream_limit) {
   122→    if (opt_data.has_value()) {
   123→      initialize(opt_data.value(), parent);
   124→      return;
   125→    }
   126→    // The static cast makes sure we call the base class host() and not
   127→    // HttpConnPoolImplBase::host which is of a different type.
   128→    Upstream::Host::CreateConnectionData data =
   129→        static_cast<Envoy::ConnectionPool::ConnPoolImplBase*>(&parent)->host()->createConnection(
   130→            parent.dispatcher(), parent.socketOptions(), parent.transportSocketOptions());
   131→    initialize(data, parent);
   132→  }
   133→
   134→  void initialize(Upstream::Host::CreateConnectionData& data, HttpConnPoolImplBase& parent) {
   135→    real_host_description_ = data.host_description_;
   136→    codec_client_ = parent.createCodecClient(data);
   137→    codec_client_->addConnectionCallbacks(*this);
   138→    Upstream::ClusterTrafficStats& traffic_stats = *parent_.host()->cluster().trafficStats();
   139→    codec_client_->setConnectionStats(
   140→        {traffic_stats.upstream_cx_rx_bytes_total_, traffic_stats.upstream_cx_rx_bytes_buffered_,
   141→         traffic_stats.upstream_cx_tx_bytes_total_, traffic_stats.upstream_cx_tx_bytes_buffered_,
   142→         &traffic_stats.bind_errors_, nullptr});
   143→  }
   144→
   145→  void initializeReadFilters() override { codec_client_->initializeReadFilters(); }
   146→  absl::optional<Http::Protocol> protocol() const override { return codec_client_->protocol(); }
   147→  void close() override { codec_client_->close(); }
   148→  virtual Http::RequestEncoder& newStreamEncoder(Http::ResponseDecoder& response_decoder) PURE;
   149→  virtual Http::RequestEncoder&
   150→  newStreamEncoder(Http::ResponseDecoderHandlePtr response_decoder_handle) PURE;
   151→  void onEvent(Network::ConnectionEvent event) override {
   152→    // Record request metrics only for successfully connected connections that handled requests
   153→    if ((event == Network::ConnectionEvent::LocalClose ||
   154→         event == Network::ConnectionEvent::RemoteClose) &&
   155→        hasHandshakeCompleted()) {
   156→      parent_.host()->cluster().trafficStats()->upstream_rq_per_cx_.recordValue(request_count_);
   157→    }
   158→    parent_.onConnectionEvent(*this, codec_client_->connectionFailureReason(), event);
   159→  }
   160→  uint32_t numActiveStreams() const override { return codec_client_->numActiveRequests(); }
   161→  uint64_t id() const override { return codec_client_->id(); }
   162→  HttpConnPoolImplBase& parent() { return *static_cast<HttpConnPoolImplBase*>(&parent_); }
   163→
   164→  Http::CodecClientPtr codec_client_;
   165→  // Request tracking for HTTP protocols
   166→  uint32_t request_count_{0};
   167→};
