   224→                              uint32_t max_configured_concurrent_streams, Stats::Counter& cx_total,
   225→                              OptRef<Upstream::Host::CreateConnectionData> data);
   226→  ~MultiplexedActiveClientBase() override = default;
   227→  // Caps max streams per connection below 2^31 to prevent overflow.
   228→  static uint32_t maxStreamsPerConnection(uint32_t max_streams_config);
   229→
   230→  // ConnPoolImpl::ActiveClient
   231→  bool closingWithIncompleteStream() const override;
   232→  RequestEncoder& newStreamEncoder(ResponseDecoder& response_decoder) override;
   233→  RequestEncoder& newStreamEncoder(ResponseDecoderHandlePtr response_decoder_handle) override;
   234→
   235→  // CodecClientCallbacks
   236→  void onStreamDestroy() override;
   237→  void onStreamReset(Http::StreamResetReason reason) override;
   238→
   239→  // Http::ConnectionCallbacks
   240→  void onGoAway(Http::GoAwayErrorCode error_code) override;
   241→  void onSettings(ReceivedSettings& settings) override;
