    86→  ActiveClient* http_client = static_cast<ActiveClient*>(&client);
    87→  auto& http_context = typedContext<HttpAttachContext>(context);
    88→  // This decoder might have already died if ConnectivityGrid is in use and TCP
    89→  // win over QUIC.
    90→  Http::ResponseDecoder& response_decoder = *http_context.decoder_;
    91→  Http::ConnectionPool::Callbacks& callbacks = *http_context.callbacks_;
    92→
    93→  // Track this request on the connection
    94→  http_client->request_count_++;
    95→
    96→  Http::RequestEncoder* new_encoder = nullptr;
    97→  if (http_context.decoder_handle_ == nullptr) {
    98→    new_encoder = &http_client->newStreamEncoder(response_decoder);
    99→  } else {
