   111→void MultiplexedActiveClientBase::onGoAway(Http::GoAwayErrorCode) {
   112→  ENVOY_CONN_LOG(debug, "remote goaway", *codec_client_);
   113→  parent_.host()->cluster().trafficStats()->upstream_cx_close_notify_.inc();
   114→  if (state() != ActiveClient::State::Draining) {
   115→    if (codec_client_->numActiveRequests() == 0) {
   116→      codec_client_->close();
   117→    } else {
   118→      parent_.transitionActiveClientState(*this, ActiveClient::State::Draining);
   119→    }
   120→  }
