   131→  if (settings.maxConcurrentStreams().has_value()) {
   132→    int64_t old_unused_capacity = currentUnusedCapacity();
   133→    // Given config limits old_unused_capacity should never exceed int32_t.
   134→    ASSERT(std::numeric_limits<int32_t>::max() >= old_unused_capacity);
   135→    if (parent().cache() && parent().origin().has_value()) {
   136→      parent().cache()->setConcurrentStreams(*parent().origin(),
   137→                                             settings.maxConcurrentStreams().value());
   138→    }
   139→    concurrent_stream_limit_ =
   140→        std::min(settings.maxConcurrentStreams().value(), configured_stream_limit_);
   141→
   142→    int64_t delta = old_unused_capacity - currentUnusedCapacity();
   143→    if (state() == ActiveClient::State::Ready && currentUnusedCapacity() <= 0) {
   144→      parent_.transitionActiveClientState(*this, ActiveClient::State::Busy);
   145→    } else if (state() == ActiveClient::State::Busy && currentUnusedCapacity() > 0) {
   146→      parent_.transitionActiveClientState(*this, ActiveClient::State::Ready);
   147→    }
   148→
   149→    if (delta > 0) {
   150→      parent_.decrClusterStreamCapacity(delta);
   151→      ENVOY_CONN_LOG(trace, "Decreasing stream capacity by {}", *codec_client_, delta);
   152→    } else if (delta < 0) {
   153→      parent_.incrClusterStreamCapacity(-delta);
   154→      ENVOY_CONN_LOG(trace, "Increasing stream capacity by {}", *codec_client_, -delta);
   155→    }
   156→  }
   157→}
   158→
   159→void MultiplexedActiveClientBase::onStreamDestroy() {
   160→  parent().onStreamClosed(*this, false);
   161→
   162→  // If we are destroying this stream because of a disconnect, do not check for drain here. We will
   163→  // wait until the connection has been fully drained of streams and then check in the connection
   164→  // event callback.
   165→  if (!closed_with_active_rq_) {
   166→    parent().checkForIdleAndCloseIdleConnsIfDraining();
   167→  }
   168→}
   169→
   170→void MultiplexedActiveClientBase::onStreamReset(Http::StreamResetReason reason) {
   171→  switch (reason) {
   172→  case StreamResetReason::ConnectionTermination:
   173→  case StreamResetReason::LocalConnectionFailure:
   174→  case StreamResetReason::RemoteConnectionFailure:
   175→  case StreamResetReason::ConnectionTimeout:
   176→    parent_.host()->cluster().trafficStats()->upstream_rq_pending_failure_eject_.inc();
   177→    closed_with_active_rq_ = true;
   178→    break;
   179→  case StreamResetReason::LocalReset:
   180→  case StreamResetReason::ProtocolError:
   181→  case StreamResetReason::OverloadManager:
   182→    parent_.host()->cluster().trafficStats()->upstream_rq_tx_reset_.inc();
   183→    break;
   184→  case StreamResetReason::RemoteReset:
   185→    parent_.host()->cluster().trafficStats()->upstream_rq_rx_reset_.inc();
   186→    break;
   187→  case StreamResetReason::LocalRefusedStreamReset:
   188→  case StreamResetReason::RemoteRefusedStreamReset:
   189→  case StreamResetReason::Overflow:
   190→  case StreamResetReason::ConnectError:
   191→  case StreamResetReason::Http1PrematureUpstreamHalfClose:
   192→    break;
   193→  }
   194→}
   195→
   196→uint32_t MultiplexedActiveClientBase::maxStreamsPerConnection(uint32_t max_streams_config) {
   197→  return (max_streams_config != 0) ? max_streams_config : DEFAULT_MAX_STREAMS;
   198→}
   199→
   200→MultiplexedActiveClientBase::MultiplexedActiveClientBase(
   201→    HttpConnPoolImplBase& parent, uint32_t effective_concurrent_streams,
   202→    uint32_t max_configured_concurrent_streams, Stats::Counter& cx_total,
   203→    OptRef<Upstream::Host::CreateConnectionData> data)
   204→    : Envoy::Http::ActiveClient(
   205→          parent, maxStreamsPerConnection(parent.host()->cluster().maxRequestsPerConnection()),
   206→          effective_concurrent_streams, max_configured_concurrent_streams, data) {
   207→  codec_client_->setCodecClientCallbacks(*this);
   208→  codec_client_->setCodecConnectionCallbacks(*this);
   209→  cx_total.inc();
   210→}
   211→
   212→bool MultiplexedActiveClientBase::closingWithIncompleteStream() const {
   213→  return closed_with_active_rq_;
   214→}
   215→
   216→RequestEncoder& MultiplexedActiveClientBase::newStreamEncoder(ResponseDecoder& response_decoder) {
   217→  return codec_client_->newStream(response_decoder);
   218→}
   219→
   220→RequestEncoder&
   221→MultiplexedActiveClientBase::newStreamEncoder(ResponseDecoderHandlePtr response_decoder_handle) {
   222→  return codec_client_->newStream(std::move(response_decoder_handle));
   223→}
   224→
   225→} // namespace Http
   226→} // namespace Envoy
   227→

