   141→  Stats::TimespanPtr conn_length_;
   142→  Event::TimerPtr connect_timer_;
   143→  Event::TimerPtr connection_duration_timer_;
   144→  bool resources_released_{false};
   145→  bool timed_out_{false};
   146→  // TODO(danzh) remove this once http codec exposes the handshake state for h3.
   147→  bool has_handshake_completed_{false};
   148→
   149→protected:
   150→  // HTTP/3 subclass should override this.
   151→  virtual bool supportsEarlyData() const { return false; }
   152→
   153→private:
   154→  State state_{State::Connecting};
   155→};
