   160→public:
   161→  PendingStream(ConnPoolImplBase& parent, bool can_send_early_data);
   162→  ~PendingStream() override;
   163→
   164→  // ConnectionPool::Cancellable
   165→  void cancel(Envoy::ConnectionPool::CancelPolicy policy) override;
