   201→  }
   202→
   203→  // Determines if prefetching is warranted based on the number of streams in
   204→  // use, pending streams, anticipated and/or currently unused capacity, and
   205→  // preconnect configuration.
   206→  //
   207→  // If anticipate_incoming_stream is true this assumes a call to newStream is
   208→  // pending, which is true for global preconnect.
   209→  static bool shouldConnect(size_t pending_streams, size_t active_streams,
   210→                            int64_t connecting_and_connected_capacity, float preconnect_ratio,
   211→                            bool anticipate_incoming_stream = false);
